#!/bin/bash
set -e
TARGET="${1:-$HOME/git/happydasol}"
echo "Setting up in: $TARGET"
mkdir -p "$TARGET/project/assets"
cd "$TARGET"

echo "" | base64 --decode > "server.js"
echo "created: server.js"
echo "" | base64 --decode > "package.json"
echo "created: package.json"
echo "" | base64 --decode > "Wedding Invitation.html"
echo "created: Wedding Invitation.html"

echo ""
echo "✅ Files created!"
echo "⚠️  Now copy your hero-couple.jpeg to: $TARGET/project/assets/hero-couple.jpeg"
echo ""
read -p "Press Enter after copying the photo to continue with npm install..." _
npm install
echo ""
echo "🎬 Done! Run: npm start"
echo "   Then open: http://localhost:3000/Wedding%20Invitation.html"